// --- Maintenance mode check ---
const sshRaw = $input.first().json.stdout || '';
const maintSplit = sshRaw.split('---MAINT---');
const stateJson = (maintSplit[0] || '').trim();
const maintAndLearn = (maintSplit[1] || 'NONE').trim();
const learnSplit = maintAndLearn.split('---LEARN---');
const maintRaw = (learnSplit[0] || 'NONE').trim();
// Parse learning data (auto-suppressed scenarios)
const learnPart = learnSplit.length > 1 ? learnSplit[1].trim() : '';
const suppressedSet = new Set();
if (learnPart) {
  learnPart.split('\n').forEach(line => {
    if (line.includes('|')) suppressedSet.add(line.trim());
  });
}
let maintenanceActive = false;
let maintenanceInfo = null;
if (maintRaw !== 'NONE' && maintRaw !== '') {
  try { maintenanceInfo = JSON.parse(maintRaw); maintenanceActive = true; }
  catch(e) { maintenanceActive = true; maintenanceInfo = { reason: maintRaw }; }
}
if (maintenanceActive) {
  const stateB64 = Buffer.from(stateJson || '{}').toString('base64');
  return [{ json: { hasContent: false, needsYtIssue: false, isRepeat: false, shouldEscalate: false,
    host: '', scenario: '', sourceIp: '', stateB64,
    maintenanceSuppressed: true, maintenanceReason: maintenanceInfo?.reason || 'scheduled' }}];
}
// --- End maintenance check ---

const webhookData = $('CrowdSec Webhook').first().json;
let body;
if (webhookData.body && typeof webhookData.body === 'object' && webhookData.body.body) { body = webhookData.body.body; }
else if (webhookData.body && typeof webhookData.body === 'object') { body = webhookData.body; }
else { body = webhookData; }
if (typeof body === 'string') { try { body = JSON.parse(body); } catch(e) { body = {}; } }

const sd = $getWorkflowStaticData('global');
if (!sd.activeAlerts) sd.activeAlerts = {};
if (!sd.hostIssues) sd.hostIssues = {};
if (!sd.currentBurst) sd.currentBurst = { startTime: 0, ips: [], fired: false };
if (!sd.closedKeys) sd.closedKeys = {};

const ACTIVE_TTL_MS = 7200000;       // 2h for active decisions
const RECOVERED_TTL_MS = 14400000;   // 4h for recovered (keeps issueId)
const BURST_WINDOW_MS = 300000;      // 5min
const BURST_THRESHOLD = 3;           // 3+ hosts with same IP
const CREATION_LOCK_MS = 60000;      // 1min
const COOLDOWN_MS = 300000;          // 5min dedup
const FLAP_ESCALATE_THRESHOLD = 2;

// Restore from persistent file on first run
if (Object.keys(sd.activeAlerts).length === 0 && Object.keys(sd.hostIssues).length === 0) {
  if (stateJson) {
    try {
      const loaded = JSON.parse(stateJson);
      if (loaded && typeof loaded === 'object') {
        sd.activeAlerts = loaded.activeAlerts || {};
        sd.hostIssues = loaded.hostIssues || {};
      }
    } catch(e) {}
  }
}

// Handle registration callback from security-triage.sh
if (body.action === 'register' && body.dedupKey && body.issueId) {
  sd.hostIssues[body.dedupKey] = { issueId: body.issueId, registeredAt: Date.now() };
  const state = { activeAlerts: sd.activeAlerts, hostIssues: sd.hostIssues };
  const stateB64 = Buffer.from(JSON.stringify(state)).toString('base64');
  return [{ json: { hasContent: false, stateB64, host: body.host || '' } }];
}

// Extract CrowdSec fields
const host = body.host || 'unknown';
const scenario = body.scenario || '';
const eventsCount = body.events_count || 0;
const sourceIp = body.source_ip || '';
const sourceCn = body.source_cn || '';
const sourceAsNumber = body.source_as_number || '';
const sourceAsName = body.source_as_name || '';
const startAt = body.start_at || '';
const stopAt = body.stop_at || '';
const decisions = Array.isArray(body.decisions) ? body.decisions : [];
const banDuration = decisions.length > 0 ? decisions[0].duration : 'none';
const decisionType = decisions.length > 0 ? decisions[0].type : 'none';

if (!scenario || !sourceIp) {
  const state = { activeAlerts: sd.activeAlerts, hostIssues: sd.hostIssues };
  const stateB64 = Buffer.from(JSON.stringify(state)).toString('base64');
  return [{ json: { hasContent: false, stateB64, host, scenario, sourceIp } }];
}

// Severity classification from scenario name
let severity = 'low';
if (scenario.match(/CVE|exploit|backdoor|log4j|rce/i)) severity = 'critical';
else if (scenario.match(/bf|brute|ssh-bf|http-generic-bf/i)) severity = 'high';
else if (scenario.match(/scan|crawl|probing|enum/i)) severity = 'medium';
else if (scenario.match(/bad-user-agent|non_statics/i)) severity = 'low';

// MITRE ATT&CK mapping
const mitreMap = {
  'crowdsecurity/ssh-bf': 'T1110.001',
  'crowdsecurity/ssh-slow-bf': 'T1110.001',
  'crowdsecurity/http-generic-bf': 'T1110',
  'crowdsecurity/http-probing': 'T1595.002',
  'crowdsecurity/http-crawl-non_statics': 'T1595.002',
  'crowdsecurity/http-sensitive-files': 'T1083',
  'crowdsecurity/http-bad-user-agent': 'T1595.002',
  'crowdsecurity/http-sqli-probing': 'T1190',
  'crowdsecurity/http-xss-probing': 'T1189',
  'crowdsecurity/http-cve-probing': 'T1190',
  'crowdsecurity/http-backdoors-attempts': 'T1505.003',
  'crowdsecurity/http-admin-interface-probing': 'T1190',
  'crowdsecurity/nginx-req-limit-exceeded': 'T1498',
  'crowdsecurity/iptables-scan-multi_ports': 'T1046',
  'crowdsecurity/smtp-spam': 'T1566',
  'crowdsecurity/dns-poisoning': 'T1557'
};
const mitreId = mitreMap[scenario] || '';
const mitreLabel = mitreId ? ' [' + mitreId + ']' : '';

// Check if this scenario+host is auto-suppressed by learning loop
const learnKey = scenario + '|' + host;
const isAutoSuppressed = suppressedSet.has(learnKey);
if (isAutoSuppressed && severity !== 'critical') {
  // Auto-suppressed by learning loop — skip (critical always bypasses)
  const state = { activeAlerts: sd.activeAlerts, hostIssues: sd.hostIssues };
  const existingStateB64 = Buffer.from(JSON.stringify(state)).toString('base64');
  return [{ json: { hasContent: false, reason: 'auto_suppressed', scenario, host, sourceIp, stateB64: existingStateB64 } }];
}

// Dedup key: host:scenario:sourceIP
const dedupKey = host + ':' + scenario + ':' + sourceIp;

// Short cooldown dedup
if (sd.closedKeys[dedupKey]) {
  const closedAge = Date.now() - sd.closedKeys[dedupKey];
  if (closedAge < COOLDOWN_MS) {
    const state = { activeAlerts: sd.activeAlerts, hostIssues: sd.hostIssues };
    const stateB64 = Buffer.from(JSON.stringify(state)).toString('base64');
    return [{ json: { hasContent: false, stateB64, host, scenario, sourceIp,
      suppressed: true, suppressReason: 'cooldown' } }];
  } else {
    delete sd.closedKeys[dedupKey];
  }
}

// Flap detection + active alert tracking
let flapCount = 0;
let isRepeat = false;
let existingIssueId = '';
let commentText = '';
let repeatAction = 'none';
let shouldEscalate = false;
let isBurstCorrelation = false;
let burstHosts = '';

const existing = sd.activeAlerts[dedupKey];
if (existing) {
  // Alert already seen
  if (existing.recoveredAt) {
    // Was recovered, now firing again = flap
    existing.flapCount = (existing.flapCount || 0) + 1;
    delete existing.recoveredAt;
  }
  existing.lastSeen = Date.now();
  existing.count = (existing.count || 1) + 1;
  flapCount = existing.flapCount || 0;
  isRepeat = true;

  // Check for existing YT issue via hostIssues
  const issueEntry = sd.hostIssues[dedupKey];
  existingIssueId = issueEntry ? issueEntry.issueId || '' : '';

  commentText = 'CrowdSec alert re-fired: ' + scenario.replace('crowdsecurity/', '') + ' from ' + sourceIp +
    ' on ' + host + ' at ' + new Date().toISOString() +
    ' (count: ' + existing.count + (flapCount > 0 ? ', flap #' + flapCount : '') + ')';

  if (existingIssueId) {
    repeatAction = 'check_yt';
  } else {
    // No issue yet, check creation lock
    if (existing.firstSeen && (Date.now() - existing.firstSeen < CREATION_LOCK_MS)) {
      const state = { activeAlerts: sd.activeAlerts, hostIssues: sd.hostIssues };
      const stateB64 = Buffer.from(JSON.stringify(state)).toString('base64');
      return [{ json: { hasContent: false, stateB64, host, scenario, sourceIp,
        suppressed: true, suppressReason: 'creation_lock' } }];
    }
    isRepeat = false;
    repeatAction = 'none';
  }
} else {
  // First time seeing this dedup key
  sd.activeAlerts[dedupKey] = {
    firstSeen: Date.now(), lastSeen: Date.now(), count: 1, flapCount: 0,
    host, scenario, sourceIp
  };
}

// Burst/cross-host correlation: same sourceIP on 3+ different hosts
if (severity !== 'low') {
  const now_b = Date.now();
  if (sd.currentBurst.startTime && (now_b - sd.currentBurst.startTime > BURST_WINDOW_MS)) {
    sd.currentBurst = { startTime: 0, ips: [], fired: false };
  }
  // Track IPs with their hosts
  const alreadyTracked = sd.currentBurst.ips.some(e => e.ip === sourceIp && e.host === host);
  if (!alreadyTracked) {
    if (!sd.currentBurst.startTime) sd.currentBurst.startTime = now_b;
    sd.currentBurst.ips.push({ ip: sourceIp, host, scenario });
  }
  // Count distinct hosts for this IP
  const hostsForIp = [...new Set(sd.currentBurst.ips.filter(e => e.ip === sourceIp).map(e => e.host))];
  if (hostsForIp.length >= BURST_THRESHOLD && !sd.currentBurst.fired) {
    sd.currentBurst.fired = true;
    isBurstCorrelation = true;
    burstHosts = hostsForIp.join(',');
  }
}

// Escalation: severity=critical OR flapCount >= 2 OR isBurstCorrelation
if (severity === 'critical' || flapCount >= FLAP_ESCALATE_THRESHOLD || isBurstCorrelation) {
  shouldEscalate = true;
}

// Determine if YT issue needed: high or critical severity
const needsYtIssue = (severity === 'critical' || severity === 'high') && !isRepeat;

// TTL pruning
const now = Date.now();
for (const k of Object.keys(sd.activeAlerts)) {
  const entry = sd.activeAlerts[k];
  if (!entry) { delete sd.activeAlerts[k]; continue; }
  if (entry.recoveredAt) {
    if (now - entry.recoveredAt > RECOVERED_TTL_MS) delete sd.activeAlerts[k];
  } else if (entry.lastSeen) {
    if (now - entry.lastSeen > ACTIVE_TTL_MS) delete sd.activeAlerts[k];
  } else {
    delete sd.activeAlerts[k];
  }
}
for (const k of Object.keys(sd.hostIssues)) {
  if (sd.hostIssues[k].registeredAt && now - sd.hostIssues[k].registeredAt > RECOVERED_TTL_MS) {
    delete sd.hostIssues[k];
  }
}
for (const k of Object.keys(sd.closedKeys)) {
  if (now - sd.closedKeys[k] > 1800000) delete sd.closedKeys[k];
}
if (sd.currentBurst.startTime && (now - sd.currentBurst.startTime > 600000)) {
  sd.currentBurst = { startTime: 0, ips: [], fired: false };
}

const state = { activeAlerts: sd.activeAlerts, hostIssues: sd.hostIssues };
const stateB64 = Buffer.from(JSON.stringify(state)).toString('base64');

// Build Matrix message
const sevEmoji = { critical: '\ud83d\udd34', high: '\ud83d\udfe0', medium: '\ud83d\udfe1', low: '\u26aa' };
const emoji = sevEmoji[severity] || '\u26aa';
const flapLabel = flapCount > 0 ? ' [FLAPPING x' + flapCount + ']' : '';
const burstLabel = isBurstCorrelation ? ' [BURST: ' + burstHosts + ']' : '';
const scenarioShort = scenario.replace('crowdsecurity/', '');

const matrixBody = emoji + ' [CrowdSec] ' + scenarioShort + mitreLabel + ' on ' + host + flapLabel + burstLabel +
  '\nSource: ' + sourceIp + ' (' + sourceCn + (sourceAsName ? ', AS' + sourceAsNumber + ' ' + sourceAsName : '') + ')' +
  '\nEvents: ' + eventsCount + ' | Action: ' + decisionType + ' ' + banDuration +
  (isRepeat && existingIssueId ? '\nTracking: ' + existingIssueId : '');

const matrixHtml = emoji + ' <b>[CrowdSec]</b> <code>' + scenarioShort + '</code>' + mitreLabel + ' on <b>' + host + '</b>' + flapLabel + burstLabel +
  '<br>Source: <code>' + sourceIp + '</code> (' + sourceCn + (sourceAsName ? ', AS' + sourceAsNumber + ' ' + sourceAsName : '') + ')' +
  '<br>Events: ' + eventsCount + ' | Action: ' + decisionType + ' ' + banDuration +
  (isRepeat && existingIssueId ? '<br>Tracking: <b>' + existingIssueId + '</b>' : '');

// YT issue fields
const ytSummary = 'CrowdSec: ' + scenarioShort + ' from ' + sourceIp + ' on ' + host;
let ytDesc = '## CrowdSec Alert\n\n| Field | Value |\n|-------|-------|\n| Host | `' + host + '` |\n| Scenario | `' + scenario +
  ' + '` |\n| Source IP | ' + sourceIp + ' (' + sourceCn + (sourceAsName ? ', AS' + sourceAsNumber + ' ' + sourceAsName : '') + ') |\n' +
  '| Events | ' + eventsCount + ' |\n| Decision | ' + decisionType + ' ' + banDuration + ' |\n' +
  '| Time | ' + startAt + ' to ' + stopAt + ' |\n' +
  '| Severity | **' + severity + '** |\n';
if (flapCount > 0) ytDesc += '| Flap count | ' + flapCount + ' |\n';
if (isBurstCorrelation) ytDesc += '\n---\n\n**Cross-host burst:** ' + burstHosts;

return [{ json: {
  hasContent: true, host, scenario, scenarioShort, eventsCount, sourceIp, sourceCn,
  sourceAsNumber, sourceAsName, startAt, stopAt, decisions, banDuration, decisionType,
  severity, dedupKey, flapCount, flapLabel, isBurstCorrelation, burstHosts,
  isRepeat, existingIssueId, needsYtIssue, shouldEscalate, repeatAction,
  commentText, matrixBody, matrixHtml, ytSummary, ytDesc, stateB64, mitreId
} }];

const parseAlert = $('Parse Alert').first().json;
const ytResponse = $input.first().json;
let repeatAction = 'comment';
let ytState = 'unknown';
try {
  const customFields = ytResponse.customFields || [];
  const stateField = customFields.find(f => f.name === 'State');
  if (stateField && stateField.value) {
    ytState = stateField.value.name || 'unknown';
  }
} catch(e) {
  ytState = 'unknown';
}
if (!ytResponse.id && !ytResponse.idReadable) {
  repeatAction = 'new';
} else if (ytState === 'Done' || ytState === 'Cancelled' || ytState === 'Duplicate') {
  repeatAction = 'new';
  const sd = $getWorkflowStaticData('global');
  if (sd.hostIssues && sd.hostIssues[parseAlert.dedupKey]) {
    sd.hostIssues[parseAlert.dedupKey].issueId = null;
  }
} else if (ytState === 'To Verify') {
  repeatAction = 'reopen';
} else {
  repeatAction = 'comment';
}
return [{ json: { ...parseAlert, repeatAction, ytState } }];

const parseData = $('Parse Alert').first().json;
const ytResponse = $input.first().json;
const issueId = ytResponse.idReadable || '';
const dedupKey = parseData.dedupKey;
const sd = $getWorkflowStaticData('global');
if (!sd.hostIssues) sd.hostIssues = {};
if (issueId) {
  sd.hostIssues[dedupKey] = { issueId: issueId, registeredAt: Date.now() };
}
const state = { activeAlerts: sd.activeAlerts || {}, hostIssues: sd.hostIssues };
const stateB64 = Buffer.from(JSON.stringify(state)).toString('base64');
return [{ json: { ...parseData, registeredIssueId: issueId, stateB64 } }];

// --- Maintenance mode check ---
const sshRaw = $input.first().json.stdout || '';
const maintSplit = sshRaw.split('---MAINT---');
const stateJson = (maintSplit[0] || '').trim();
const maintAndLearn = (maintSplit[1] || 'NONE').trim();
const learnSplit = maintAndLearn.split('---LEARN---');
const maintRaw = (learnSplit[0] || 'NONE').trim();
// Parse learning data (auto-suppressed scenarios)
const learnPart = learnSplit.length > 1 ? learnSplit[1].trim() : '';
const suppressedSet = new Set();
if (learnPart) {
  learnPart.split('\n').forEach(line => {
    if (line.includes('|')) suppressedSet.add(line.trim());
  });
}
let maintenanceActive = false;
let maintenanceInfo = null;
if (maintRaw !== 'NONE' && maintRaw !== '') {
  try { maintenanceInfo = JSON.parse(maintRaw); maintenanceActive = true; }
  catch(e) { maintenanceActive = true; maintenanceInfo = { reason: maintRaw }; }
}
if (maintenanceActive) {
  const stateB64 = Buffer.from(stateJson || '{}').toString('base64');
  return [{ json: { hasContent: false, needsYtIssue: false, isRepeat: false, shouldEscalate: false,
    host: '', scenario: '', sourceIp: '', stateB64,
    maintenanceSuppressed: true, maintenanceReason: maintenanceInfo?.reason || 'scheduled' }}];
}
// --- End maintenance check ---

const webhookData = $('CrowdSec Webhook').first().json;
let body;
if (webhookData.body && typeof webhookData.body === 'object' && webhookData.body.body) { body = webhookData.body.body; }
else if (webhookData.body && typeof webhookData.body === 'object') { body = webhookData.body; }
else { body = webhookData; }
if (typeof body === 'string') { try { body = JSON.parse(body); } catch(e) { body = {}; } }

const sd = $getWorkflowStaticData('global');
if (!sd.activeAlerts) sd.activeAlerts = {};
if (!sd.hostIssues) sd.hostIssues = {};
if (!sd.currentBurst) sd.currentBurst = { startTime: 0, ips: [], fired: false };
if (!sd.closedKeys) sd.closedKeys = {};

const ACTIVE_TTL_MS = 7200000;       // 2h for active decisions
const RECOVERED_TTL_MS = 14400000;   // 4h for recovered (keeps issueId)
const BURST_WINDOW_MS = 300000;      // 5min
const BURST_THRESHOLD = 3;           // 3+ hosts with same IP
const CREATION_LOCK_MS = 60000;      // 1min
const COOLDOWN_MS = 300000;          // 5min dedup
const FLAP_ESCALATE_THRESHOLD = 2;

// Restore from persistent file on first run
if (Object.keys(sd.activeAlerts).length === 0 && Object.keys(sd.hostIssues).length === 0) {
  if (stateJson) {
    try {
      const loaded = JSON.parse(stateJson);
      if (loaded && typeof loaded === 'object') {
        sd.activeAlerts = loaded.activeAlerts || {};
        sd.hostIssues = loaded.hostIssues || {};
      }
    } catch(e) {}
  }
}

// Handle registration callback from security-triage.sh
if (body.action === 'register' && body.dedupKey && body.issueId) {
  sd.hostIssues[body.dedupKey] = { issueId: body.issueId, registeredAt: Date.now() };
  const state = { activeAlerts: sd.activeAlerts, hostIssues: sd.hostIssues };
  const stateB64 = Buffer.from(JSON.stringify(state)).toString('base64');
  return [{ json: { hasContent: false, stateB64, host: body.host || '' } }];
}

// Extract CrowdSec fields
const host = body.host || 'unknown';
const scenario = body.scenario || '';
const eventsCount = body.events_count || 0;
const sourceIp = body.source_ip || '';
const sourceCn = body.source_cn || '';
const sourceAsNumber = body.source_as_number || '';
const sourceAsName = body.source_as_name || '';
const startAt = body.start_at || '';
const stopAt = body.stop_at || '';
const decisions = Array.isArray(body.decisions) ? body.decisions : [];
const banDuration = decisions.length > 0 ? decisions[0].duration : 'none';
const decisionType = decisions.length > 0 ? decisions[0].type : 'none';

if (!scenario || !sourceIp) {
  const state = { activeAlerts: sd.activeAlerts, hostIssues: sd.hostIssues };
  const stateB64 = Buffer.from(JSON.stringify(state)).toString('base64');
  return [{ json: { hasContent: false, stateB64, host, scenario, sourceIp } }];
}

// Severity classification from scenario name
let severity = 'low';
if (scenario.match(/CVE|exploit|backdoor|log4j|rce/i)) severity = 'critical';
else if (scenario.match(/bf|brute|ssh-bf|http-generic-bf/i)) severity = 'high';
else if (scenario.match(/scan|crawl|probing|enum/i)) severity = 'medium';
else if (scenario.match(/bad-user-agent|non_statics/i)) severity = 'low';

// MITRE ATT&CK mapping
const mitreMap = {
  'crowdsecurity/ssh-bf': 'T1110.001',
  'crowdsecurity/ssh-slow-bf': 'T1110.001',
  'crowdsecurity/http-generic-bf': 'T1110',
  'crowdsecurity/http-probing': 'T1595.002',
  'crowdsecurity/http-crawl-non_statics': 'T1595.002',
  'crowdsecurity/http-sensitive-files': 'T1083',
  'crowdsecurity/http-bad-user-agent': 'T1595.002',
  'crowdsecurity/http-sqli-probing': 'T1190',
  'crowdsecurity/http-xss-probing': 'T1189',
  'crowdsecurity/http-cve-probing': 'T1190',
  'crowdsecurity/http-backdoors-attempts': 'T1505.003',
  'crowdsecurity/http-admin-interface-probing': 'T1190',
  'crowdsecurity/nginx-req-limit-exceeded': 'T1498',
  'crowdsecurity/iptables-scan-multi_ports': 'T1046',
  'crowdsecurity/smtp-spam': 'T1566',
  'crowdsecurity/dns-poisoning': 'T1557'
};
const mitreId = mitreMap[scenario] || '';
const mitreLabel = mitreId ? ' [' + mitreId + ']' : '';

// Check if this scenario+host is auto-suppressed by learning loop
const learnKey = scenario + '|' + host;
const isAutoSuppressed = suppressedSet.has(learnKey);
if (isAutoSuppressed && severity !== 'critical') {
  // Auto-suppressed by learning loop — skip (critical always bypasses)
  const state = { activeAlerts: sd.activeAlerts, hostIssues: sd.hostIssues };
  const existingStateB64 = Buffer.from(JSON.stringify(state)).toString('base64');
  return [{ json: { hasContent: false, reason: 'auto_suppressed', scenario, host, sourceIp, stateB64: existingStateB64 } }];
}

// Dedup key: host:scenario:sourceIP
const dedupKey = host + ':' + scenario + ':' + sourceIp;

// Short cooldown dedup
if (sd.closedKeys[dedupKey]) {
  const closedAge = Date.now() - sd.closedKeys[dedupKey];
  if (closedAge < COOLDOWN_MS) {
    const state = { activeAlerts: sd.activeAlerts, hostIssues: sd.hostIssues };
    const stateB64 = Buffer.from(JSON.stringify(state)).toString('base64');
    return [{ json: { hasContent: false, stateB64, host, scenario, sourceIp,
      suppressed: true, suppressReason: 'cooldown' } }];
  } else {
    delete sd.closedKeys[dedupKey];
  }
}

// Flap detection + active alert tracking
let flapCount = 0;
let isRepeat = false;
let existingIssueId = '';
let commentText = '';
let repeatAction = 'none';
let shouldEscalate = false;
let isBurstCorrelation = false;
let burstHosts = '';

const existing = sd.activeAlerts[dedupKey];
if (existing) {
  // Alert already seen
  if (existing.recoveredAt) {
    // Was recovered, now firing again = flap
    existing.flapCount = (existing.flapCount || 0) + 1;
    delete existing.recoveredAt;
  }
  existing.lastSeen = Date.now();
  existing.count = (existing.count || 1) + 1;
  flapCount = existing.flapCount || 0;
  isRepeat = true;

  // Check for existing YT issue via hostIssues
  const issueEntry = sd.hostIssues[dedupKey];
  existingIssueId = issueEntry ? issueEntry.issueId || '' : '';

  commentText = 'CrowdSec alert re-fired: ' + scenario.replace('crowdsecurity/', '') + ' from ' + sourceIp +
    ' on ' + host + ' at ' + new Date().toISOString() +
    ' (count: ' + existing.count + (flapCount > 0 ? ', flap #' + flapCount : '') + ')';

  if (existingIssueId) {
    repeatAction = 'check_yt';
  } else {
    // No issue yet, check creation lock
    if (existing.firstSeen && (Date.now() - existing.firstSeen < CREATION_LOCK_MS)) {
      const state = { activeAlerts: sd.activeAlerts, hostIssues: sd.hostIssues };
      const stateB64 = Buffer.from(JSON.stringify(state)).toString('base64');
      return [{ json: { hasContent: false, stateB64, host, scenario, sourceIp,
        suppressed: true, suppressReason: 'creation_lock' } }];
    }
    isRepeat = false;
    repeatAction = 'none';
  }
} else {
  // First time seeing this dedup key
  sd.activeAlerts[dedupKey] = {
    firstSeen: Date.now(), lastSeen: Date.now(), count: 1, flapCount: 0,
    host, scenario, sourceIp
  };
}

// Burst/cross-host correlation: same sourceIP on 3+ different hosts
if (severity !== 'low') {
  const now_b = Date.now();
  if (sd.currentBurst.startTime && (now_b - sd.currentBurst.startTime > BURST_WINDOW_MS)) {
    sd.currentBurst = { startTime: 0, ips: [], fired: false };
  }
  // Track IPs with their hosts
  const alreadyTracked = sd.currentBurst.ips.some(e => e.ip === sourceIp && e.host === host);
  if (!alreadyTracked) {
    if (!sd.currentBurst.startTime) sd.currentBurst.startTime = now_b;
    sd.currentBurst.ips.push({ ip: sourceIp, host, scenario });
  }
  // Count distinct hosts for this IP
  const hostsForIp = [...new Set(sd.currentBurst.ips.filter(e => e.ip === sourceIp).map(e => e.host))];
  if (hostsForIp.length >= BURST_THRESHOLD && !sd.currentBurst.fired) {
    sd.currentBurst.fired = true;
    isBurstCorrelation = true;
    burstHosts = hostsForIp.join(',');
  }
}

// Escalation: severity=critical OR flapCount >= 2 OR isBurstCorrelation
if (severity === 'critical' || flapCount >= FLAP_ESCALATE_THRESHOLD || isBurstCorrelation) {
  shouldEscalate = true;
}

// Determine if YT issue needed: high or critical severity
const needsYtIssue = (severity === 'critical' || severity === 'high') && !isRepeat;

// TTL pruning
const now = Date.now();
for (const k of Object.keys(sd.activeAlerts)) {
  const entry = sd.activeAlerts[k];
  if (!entry) { delete sd.activeAlerts[k]; continue; }
  if (entry.recoveredAt) {
    if (now - entry.recoveredAt > RECOVERED_TTL_MS) delete sd.activeAlerts[k];
  } else if (entry.lastSeen) {
    if (now - entry.lastSeen > ACTIVE_TTL_MS) delete sd.activeAlerts[k];
  } else {
    delete sd.activeAlerts[k];
  }
}
for (const k of Object.keys(sd.hostIssues)) {
  if (sd.hostIssues[k].registeredAt && now - sd.hostIssues[k].registeredAt > RECOVERED_TTL_MS) {
    delete sd.hostIssues[k];
  }
}
for (const k of Object.keys(sd.closedKeys)) {
  if (now - sd.closedKeys[k] > 1800000) delete sd.closedKeys[k];
}
if (sd.currentBurst.startTime && (now - sd.currentBurst.startTime > 600000)) {
  sd.currentBurst = { startTime: 0, ips: [], fired: false };
}

const state = { activeAlerts: sd.activeAlerts, hostIssues: sd.hostIssues };
const stateB64 = Buffer.from(JSON.stringify(state)).toString('base64');

// Build Matrix message
const sevEmoji = { critical: '\ud83d\udd34', high: '\ud83d\udfe0', medium: '\ud83d\udfe1', low: '\u26aa' };
const emoji = sevEmoji[severity] || '\u26aa';
const flapLabel = flapCount > 0 ? ' [FLAPPING x' + flapCount + ']' : '';
const burstLabel = isBurstCorrelation ? ' [BURST: ' + burstHosts + ']' : '';
const scenarioShort = scenario.replace('crowdsecurity/', '');

const matrixBody = emoji + ' [CrowdSec] ' + scenarioShort + mitreLabel + ' on ' + host + flapLabel + burstLabel +
  '\nSource: ' + sourceIp + ' (' + sourceCn + (sourceAsName ? ', AS' + sourceAsNumber + ' ' + sourceAsName : '') + ')' +
  '\nEvents: ' + eventsCount + ' | Action: ' + decisionType + ' ' + banDuration +
  (isRepeat && existingIssueId ? '\nTracking: ' + existingIssueId : '');

const matrixHtml = emoji + ' <b>[CrowdSec]</b> <code>' + scenarioShort + '</code>' + mitreLabel + ' on <b>' + host + '</b>' + flapLabel + burstLabel +
  '<br>Source: <code>' + sourceIp + '</code> (' + sourceCn + (sourceAsName ? ', AS' + sourceAsNumber + ' ' + sourceAsName : '') + ')' +
  '<br>Events: ' + eventsCount + ' | Action: ' + decisionType + ' ' + banDuration +
  (isRepeat && existingIssueId ? '<br>Tracking: <b>' + existingIssueId + '</b>' : '');

// YT issue fields
const ytSummary = 'CrowdSec: ' + scenarioShort + ' from ' + sourceIp + ' on ' + host;
let ytDesc = '## CrowdSec Alert\n\n| Field | Value |\n|-------|-------|\n| Host | `' + host + '` |\n| Scenario | `' + scenario +
  ' + '` |\n| Source IP | ' + sourceIp + ' (' + sourceCn + (sourceAsName ? ', AS' + sourceAsNumber + ' ' + sourceAsName : '') + ') |\n' +
  '| Events | ' + eventsCount + ' |\n| Decision | ' + decisionType + ' ' + banDuration + ' |\n' +
  '| Time | ' + startAt + ' to ' + stopAt + ' |\n' +
  '| Severity | **' + severity + '** |\n';
if (flapCount > 0) ytDesc += '| Flap count | ' + flapCount + ' |\n';
if (isBurstCorrelation) ytDesc += '\n---\n\n**Cross-host burst:** ' + burstHosts;

return [{ json: {
  hasContent: true, host, scenario, scenarioShort, eventsCount, sourceIp, sourceCn,
  sourceAsNumber, sourceAsName, startAt, stopAt, decisions, banDuration, decisionType,
  severity, dedupKey, flapCount, flapLabel, isBurstCorrelation, burstHosts,
  isRepeat, existingIssueId, needsYtIssue, shouldEscalate, repeatAction,
  commentText, matrixBody, matrixHtml, ytSummary, ytDesc, stateB64, mitreId
} }];

const parseAlert = $('Parse Alert').first().json;
const ytResponse = $input.first().json;
let repeatAction = 'comment';
let ytState = 'unknown';
try {
  const customFields = ytResponse.customFields || [];
  const stateField = customFields.find(f => f.name === 'State');
  if (stateField && stateField.value) {
    ytState = stateField.value.name || 'unknown';
  }
} catch(e) {
  ytState = 'unknown';
}
if (!ytResponse.id && !ytResponse.idReadable) {
  repeatAction = 'new';
} else if (ytState === 'Done' || ytState === 'Cancelled' || ytState === 'Duplicate') {
  repeatAction = 'new';
  const sd = $getWorkflowStaticData('global');
  if (sd.hostIssues && sd.hostIssues[parseAlert.dedupKey]) {
    sd.hostIssues[parseAlert.dedupKey].issueId = null;
  }
} else if (ytState === 'To Verify') {
  repeatAction = 'reopen';
} else {
  repeatAction = 'comment';
}
return [{ json: { ...parseAlert, repeatAction, ytState } }];

const parseData = $('Parse Alert').first().json;
const ytResponse = $input.first().json;
const issueId = ytResponse.idReadable || '';
const dedupKey = parseData.dedupKey;
const sd = $getWorkflowStaticData('global');
if (!sd.hostIssues) sd.hostIssues = {};
if (issueId) {
  sd.hostIssues[dedupKey] = { issueId: issueId, registeredAt: Date.now() };
}
const state = { activeAlerts: sd.activeAlerts || {}, hostIssues: sd.hostIssues };
const stateB64 = Buffer.from(JSON.stringify(state)).toString('base64');
return [{ json: { ...parseData, registeredIssueId: issueId, stateB64 } }];
